(1218,	'dbem_event_submitted_email_admin',	'',	'yes'),
(1219,	'dbem_event_submitted_email_subject',	'Submitted Event Awaiting Approval',	'yes'),
(1220,	'dbem_event_submitted_email_body',	'A new event has been submitted by #_CONTACTNAME.\r\n\r\nName : #_EVENTNAME \r\n\r\nDate : #_EVENTDATES \r\n\r\nTime : #_EVENTTIMES \r\n\r\nPlease visit http://localhost:10253/wp-admin/post.php?action=edit&amp;post=#_EVENTPOSTID to review this event for approval.\r\n\r\n\r\n-------------------------------\r\n\r\nPowered by Events Manager - http://wp-events-plugin.com',	'yes'),
(1221,	'dbem_event_resubmitted_email_subject',	'Re-Submitted Event Awaiting Approval',	'yes'),
(1222,	'dbem_event_resubmitted_email_body',	'A previously published event has been modified by #_CONTACTNAME, and this event is now unpublished and pending your approval.\r\n\r\nName : #_EVENTNAME \r\n\r\nDate : #_EVENTDATES \r\n\r\nTime : #_EVENTTIMES \r\n\r\nPlease visit http://localhost:10253/wp-admin/post.php?action=edit&amp;post=#_EVENTPOSTID to review this event for approval.\r\n\r\n\r\n-------------------------------\r\n\r\nPowered by Events Manager - http://wp-events-plugin.com',	'yes'),
(1223,	'dbem_event_published_email_subject',	'Published Event - #_EVENTNAME',	'yes'),
(1224,	'dbem_event_published_email_body',	'A new event has been published by #_CONTACTNAME.\r\n\r\nName : #_EVENTNAME \r\n\r\nDate : #_EVENTDATES \r\n\r\nTime : #_EVENTTIMES \r\n\r\nEdit this event - http://localhost:10253/wp-admin/post.php?action=edit&amp;post=#_EVENTPOSTID \r\n\r\n View this event - #_EVENTURL\r\n\r\n\r\n-------------------------------\r\n\r\nPowered by Events Manager - http://wp-events-plugin.com',	'yes'),
(1225,	'dbem_event_approved_email_subject',	'Event Approved - #_EVENTNAME',	'yes'),
(1226,	'dbem_event_approved_email_body',	'Dear #_CONTACTNAME\r\n\r\nYour event #_EVENTNAME on #_EVENTDATES has been approved.\r\n\r\n{not_recurring}You can view your event here: #_EVENTURL{/not_recurring}\r\n\r\n\r\n-------------------------------\r\n\r\nPowered by Events Manager - http://wp-events-plugin.com',	'yes'),
(1227,	'dbem_event_reapproved_email_subject',	'Event Approved - #_EVENTNAME',	'yes'),
(1228,	'dbem_event_reapproved_email_body',	'Dear #_CONTACTNAME\r\n\r\nYour event #_EVENTNAME on #_EVENTDATES has been approved.\r\n\r\n{not_recurring}You can view your event here: #_EVENTURL{/not_recurring}\r\n\r\n\r\n-------------------------------\r\n\r\nPowered by Events Manager - http://wp-events-plugin.com',	'yes'),
