(1243,	'dbem_single_event_format',	'<section class=\"em-item-header\" style=\"--default-border:#_CATEGORYCOLOR\">\r\n	{has_image}\r\n	<div class=\"em-item-image {no_image}has-placeholder{/no_image}\">\r\n		#_EVENTIMAGE{medium}\r\n	</div>\r\n	{/has_image}\r\n	{is_cancelled}\r\n	<div class=\"em-event-cancelled em-notice em-notice-error em-notice-icon\">\r\n		<span class=\"em-icon em-icon-cross-circle\"></span>\r\n		This event has been cancelled.	</div>\r\n	{/is_cancelled}\r\n	<div class=\"em-item-meta\">\r\n		<section class=\"em-item-meta-column\">\r\n			<section class=\"em-event-when\">\r\n				<h3>When</h3>\r\n				<div class=\"em-item-meta-line em-event-date em-event-meta-datetime\">\r\n					<span class=\"em-icon-calendar em-icon\"></span>\r\n					#_EVENTDATES    \r\n				</div>\r\n				<div class=\"em-item-meta-line em-event-time em-event-meta-datetime\">\r\n					<span class=\"em-icon-clock em-icon\"></span>\r\n					#_EVENTTIMES\r\n				</div>\r\n				#_EVENTADDTOCALENDAR\r\n			</section>\r\n	\r\n			{has_bookings}\r\n			<section class=\"em-event-bookings-meta\">\r\n				<h3>Bookings</h3>\r\n				{bookings_open}\r\n				<div class=\"em-item-meta-line em-event-prices\">\r\n					<span class=\"em-icon-ticket em-icon\"></span>\r\n					#_EVENTPRICERANGE\r\n				</div>\r\n				<a href=\"#em-event-booking-form\" class=\"button input with-icon-right\">\r\n										<span class=\"em-icon-ticket em-icon\"></span>\r\n				</a>\r\n				{/bookings_open}\r\n				{bookings_closed}\r\n				<div class=\"em-item-meta-line em-event-prices\">\r\n					<span class=\"em-icon-ticket em-icon\"></span>\r\n					Bookings closed				</div>\r\n				{/bookings_closed}\r\n			</section>\r\n			{/has_bookings}\r\n		</section>\r\n\r\n		<section class=\"em-item-meta-column\">\r\n			{has_location_venue}\r\n			<section class=\"em-event-where\">\r\n				<h3>Where</h3>\r\n				<div class=\"em-item-meta-line em-event-location\">\r\n					<span class=\"em-icon-location em-icon\"></span>\r\n					<div>\r\n						#_LOCATIONLINK<br>\r\n						#_LOCATIONFULLLINE\r\n					</div>\r\n				</div>\r\n			</section>\r\n			{/has_location_venue}\r\n			{has_event_location}\r\n			<section class=\"em-event-where\">\r\n				<h3>Where</h3>\r\n				<div class=\"em-item-meta-line em-event-location\">\r\n					<span class=\"em-icon-at em-icon\"></span>\r\n					#_EVENTLOCATION\r\n				</div>\r\n			</section>\r\n			{/has_event_location}\r\n			\r\n			{has_taxonomy}\r\n			<section class=\"em-item-taxonomies\">\r\n				<h3>Event Type</h3>\r\n				{has_category}\r\n				<div class=\"em-item-meta-line em-item-taxonomy em-event-categories\">\r\n					<span class=\"em-icon-category em-icon\"></span>\r\n					<div>#_EVENTCATEGORIES</div>\r\n				</div>\r\n				{/has_category}\r\n				{has_tag}\r\n				<div class=\"em-item-meta-line em-item-taxonomy em-event-tags\">\r\n					<span class=\"em-icon-tag em-icon\"></span>\r\n					<div>#_EVENTTAGS</div>\r\n				</div>\r\n				{/has_tag}\r\n			</section>\r\n			{/has_taxonomy}\r\n		</section>\r\n	</div>\r\n</section>\r\n{has_location_venue}\r\n<section class=\"em-event-location\">\r\n	#_LOCATIONMAP{100%,0}\r\n</section>\r\n{/has_location_venue}\r\n<section class=\"em-event-content\">\r\n	#_EVENTNOTES\r\n</section>\r\n{has_bookings}\r\n<section class=\"em-event-bookings\">\r\n	<a name=\"em-event-booking-form\"></a>\r\n	<h2>Bookings</h2>\r\n	#_BOOKINGFORM\r\n</section>\r\n{/has_bookings}',	'yes'),
