(1304,	'dbem_tags_list_item_format',	'<div class=\"em-item em-taxonomy em-tag\" style=\"--default-border:#_TAGCOLOR\">\r\n	<div class=\"em-item-image {no_image}has-placeholder{/no_image}\">\r\n		{has_image}\r\n		#_TAGIMAGE{medium}\r\n		{/has_image}\r\n		{no_image}\r\n		<div class=\"em-item-image-placeholder\"></div>\r\n		{/no_image}\r\n	</div>\r\n	<div class=\"em-item-info\">\r\n		<h3 class=\"em-item-title\">#_TAGLINK</h3>\r\n		<div class=\"em-event-meta em-item-meta\">\r\n			{has_events}\r\n			<div class=\"em-item-meta-line em-taxonomy-events em-tag-events\">\r\n				<span class=\"em-icon-calendar em-icon\"></span>\r\n				<div>\r\n					<p>Next Event</p>\r\n					<p>#_TAGNEXTEVENT</p>\r\n					<p><a href=\"#_TAGURL\">See All</a></p>\r\n				</div>\r\n			</div>\r\n			{/has_events}\r\n			{no_events}\r\n			<div class=\"em-item-meta-line em-taxonomy-no-events em-tag-no-events\">\r\n				<span class=\"em-icon-calendar em-icon\"></span>\r\n				<div>No upcoming events</p></div>\r\n			</div>\r\n			{/no_events}\r\n		</div>\r\n		<div class=\"em-item-desc\">\r\n			#_TAGEXCERPT{25}\r\n		</div>\r\n		<div class=\"em-item-actions input\">\r\n			<a class=\"em-item-read-more button\" href=\"#_TAGURL\">More Info</a>\r\n		</div>\r\n	</div>\r\n</div>',	'yes'),
