(1370,	'dbem_calendar_preview_modal_date_format',	'<div class=\"em-item em-event\" style=\"--default-border:#_CATEGORYCOLOR\">\r\n	<div class=\"em-item-image {no_image}has-placeholder{/no_image}\" style=\"max-width:150px\">\r\n		{has_image}\r\n		#_EVENTIMAGE{150,150}\r\n		{/has_image}\r\n		{no_image}\r\n		<div class=\"em-item-image-placeholder\">\r\n			<div class=\"date\">\r\n				<span class=\"day\">#d</span>\r\n				<span class=\"month\">#M</span>\r\n			</div>\r\n		</div>\r\n		{/no_image}\r\n	</div>\r\n	<div class=\"em-item-info\">\r\n		<div class=\"em-item-name\">#_EVENTLINK</div>\r\n		<div class=\"em-item-meta\">\r\n			<div class=\"em-item-meta-line em-event-date em-event-meta-datetime\">\r\n				<span class=\"em-icon em-icon-calendar\"></span>\r\n				<span>#j #M #y</span>\r\n			</div>\r\n			<div class=\"em-item-meta-line em-event-location em-event-meta-location\">\r\n				<span class=\"em-icon em-icon-location\"></span>\r\n				<span>#_TOWN</span>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>',	'yes'),
(1371,	'dbem_calendar_preview_modal_event_format',	'<div class=\"em pixelbones em-calendar-preview em-list em-events-list\">\r\n	<div class=\"em-event em-item\" style=\"--default-border:#_CATEGORYCOLOR\">\r\n		<div class=\"em-item-image {no_image}has-placeholder{/no_image}\">\r\n			{has_image}\r\n			#_EVENTIMAGE{medium}\r\n			{/has_image}\r\n			{no_image}\r\n			<div class=\"em-item-image-placeholder\">\r\n				<div class=\"date\">\r\n					<span class=\"day\">#d</span>\r\n					<span class=\"month\">#M</span>\r\n				</div>\r\n			</div>\r\n			{/no_image}\r\n		</div>\r\n		<div class=\"em-item-info\">\r\n			<div class=\"em-event-meta em-item-meta\">\r\n				<div class=\"em-item-meta-line em-event-date em-event-meta-datetime\">\r\n					<span class=\"em-icon-calendar em-icon\"></span>\r\n					#_EVENTDATES    \r\n				</div>\r\n				<div class=\"em-item-meta-line em-event-time em-event-meta-datetime\">\r\n					<span class=\"em-icon-clock em-icon\"></span>\r\n					#_EVENTTIMES\r\n				</div>\r\n				{bookings_open}\r\n				<div class=\"em-item-meta-line em-event-prices\">\r\n					<span class=\"em-icon-ticket em-icon\"></span>\r\n					#_EVENTPRICERANGE\r\n				</div>\r\n				{/bookings_open}\r\n				{has_location_venue}\r\n				<div class=\"em-item-meta-line em-event-location\">\r\n					<span class=\"em-icon-location em-icon\"></span>\r\n					#_LOCATIONLINK\r\n				</div>\r\n				{/has_location_venue}\r\n				{has_event_location}\r\n				<div class=\"em-item-meta-line em-event-location\">\r\n					<span class=\"em-icon-at em-icon\"></span>\r\n					#_EVENTLOCATION\r\n				</div>\r\n				{/has_event_location}\r\n				{has_category}\r\n				<div class=\"em-item-meta-line em-item-taxonomy em-event-categories\">\r\n					<span class=\"em-icon-category em-icon\"></span>\r\n					<div>#_EVENTCATEGORIES</div>\r\n				</div>\r\n				{/has_category}\r\n				{has_tag}\r\n				<div class=\"em-item-meta-line em-item-taxonomy em-event-tags\">\r\n					<span class=\"em-icon-tag em-icon\"></span>\r\n					<div>#_EVENTTAGS</div>\r\n				</div>\r\n				{/has_tag}\r\n			</div>\r\n			<div class=\"em-item-desc\">\r\n				#_EVENTEXCERPT{25}\r\n			</div>\r\n			<div class=\"em-item-actions input\">\r\n				<a class=\"em-item-read-more button\" href=\"#_EVENTURL\">More Info</a>\r\n				{bookings_open}\r\n				<a class=\"em-event-book-now button\" href=\"#_EVENTURL#em-event-booking-form\">\r\n					<span class=\"em-icon em-icon-ticket\"></span>\r\n					Book Now!				</a>\r\n				{/bookings_open}\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>',	'yes'),
(1372,	'dbem_calendar_preview_tooltip_event_format',	'{has_image}\r\n<div class=\"em-item-meta em-event-image\">\r\n	#_EVENTIMAGE{300}\r\n</div>\r\n{/has_image}\r\n<div class=\"em-item-info\">\r\n	<div class=\"em-item-title em-event-title\">#_EVENTLINK</div>\r\n	<div class=\"em-event-meta em-item-meta\">\r\n		<div class=\"em-item-meta-line em-event-date em-event-meta-datetime\">\r\n			<span class=\"em-icon-calendar em-icon\"></span>\r\n			#_EVENTDATES    \r\n		</div>\r\n		<div class=\"em-item-meta-line em-event-time em-event-meta-datetime\">\r\n			<span class=\"em-icon-clock em-icon\"></span>\r\n			#_EVENTTIMES\r\n		</div>\r\n		{bookings_open}\r\n		<div class=\"em-item-meta-line em-event-prices\">\r\n			<span class=\"em-icon-ticket em-icon\"></span>\r\n			#_EVENTPRICERANGE\r\n		</div>\r\n		{/bookings_open}\r\n		{has_location_venue}\r\n		<div class=\"em-item-meta-line em-event-location\">\r\n			<span class=\"em-icon-location em-icon\"></span>\r\n			#_LOCATIONLINK\r\n		</div>\r\n		{/has_location_venue}\r\n		{has_event_location}\r\n		<div class=\"em-item-meta-line em-event-location\">\r\n			<span class=\"em-icon-at em-icon\"></span>\r\n			#_EVENTLOCATION\r\n		</div>\r\n		{/has_event_location}\r\n		{has_category}\r\n		<div class=\"em-item-meta-line em-item-taxonomy em-event-categories\">\r\n			<span class=\"em-icon-category em-icon\"></span>\r\n			#_EVENTCATEGORIES\r\n		</div>\r\n		{/has_category}\r\n		{has_tag}\r\n		<div class=\"em-item-meta-line em-item-taxonomy em-event-tags\">\r\n			<span class=\"em-icon-tag em-icon\"></span>\r\n			<div>#_EVENTTAGS</div>\r\n		</div>\r\n		{/has_tag}\r\n	</div>\r\n</div>\r\n<div class=\"em-item-desc\">#_EVENTEXCERPT{25,...}</div>\r\n<div class=\"em-item-actions input\">\r\n	<a class=\"em-event-read-more button\" href=\"#_EVENTURL\">More Info</a>\r\n	{bookings_open}\r\n	<a class=\"em-event-book-now button\" href=\"#_EVENTURL#em-booking\">Book Now!</a>\r\n	{/bookings_open}\r\n</div>',	'yes'),
