(962,	189,	'arbeitsgruppen_0_name',	'AG Bildung'),
(963,	189,	'_arbeitsgruppen_0_name',	'field_64f72fca9a645'),
(964,	189,	'arbeitsgruppen_0_beschreibung',	'Die AG Bildung beschäftigt sich mit allen Bildungsfragen in einer Kultur der Digitalität. Welche Lehr- und Lernernsettings, -prozesse und -rollen in der Digitalen Transformation notwendig sind und wie diese erreicht werden können, sind dabei zentrale Fragen.\r\n\r\nLernen betrachten wir als lebenslange Aufgabe, somit in allen Alters- und Lebensphasen. Wir setzen mit Textbeiträgen, Projekten und Veranstaltungen notwendige Impulse und führen einen Austausch und Dialog mit der Politik, Verwaltung und Zivilgesellschaft.'),
(965,	189,	'_arbeitsgruppen_0_beschreibung',	'field_64f72fd09a646'),
(966,	189,	'arbeitsgruppen_0_koordination',	'a:2:{i:0;s:2:\"49\";i:1;s:2:\"50\";}'),
(967,	189,	'_arbeitsgruppen_0_koordination',	'field_64f72fec9a647'),
(968,	189,	'arbeitsgruppen_1_name',	'AG Datenschutz'),
(969,	189,	'_arbeitsgruppen_1_name',	'field_64f72fca9a645'),
(970,	189,	'arbeitsgruppen_1_beschreibung',	'Die AG Datenschutz beschäftigt sich mit allem rund um Daten: Wie sie zum Wohl der Bevölkerung eingesetzt werden können und wie die Privatsphäre aller Bürger:innen geschützt werden kann. Dabei geht es um Tracking im Internet, Gesichtserkennung, Videoüberwachung und Open Data.'),
(971,	189,	'_arbeitsgruppen_1_beschreibung',	'field_64f72fd09a646'),
