(974,	189,	'arbeitsgruppen_2_name',	'AG Digitale Demokratie '),
(975,	189,	'_arbeitsgruppen_2_name',	'field_64f72fca9a645'),
(976,	189,	'arbeitsgruppen_2_beschreibung',	'Die AG Digitale Demokratie beschäftigt sich mit dem Einfluss der Digitalisierung auf unsere Gesellschaft und politische Strukturen. Als Schwerpunkte setzen wir uns mit Desinformationen &amp; Plattformen, systemischen Fragen sowie Partizipation auseinander. Dazu entwickeln wir Leitlinien für eine digitalisierte Demokratie. Im Superwahljahr 2021 entwerfen wir Verhaltensrichtlinien für Parteien im Wahlkampf sowie Leitfäden für Kandidierende für den Umgang mit Desinformationen, Fakes und Shitstorms.'),
