(1184,	221,	'_wp_attachment_metadata',	'a:6:{s:5:\"width\";i:1920;s:6:\"height\";i:1080;s:4:\"file\";s:17:\"2023/08/ampel.jpg\";s:8:\"filesize\";i:106524;s:5:\"sizes\";a:10:{s:6:\"medium\";a:5:{s:4:\"file\";s:17:\"ampel-300x169.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:5425;}s:5:\"large\";a:5:{s:4:\"file\";s:18:\"ampel-1024x576.jpg\";s:5:\"width\";i:1024;s:6:\"height\";i:576;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:57456;}s:9:\"thumbnail\";a:5:{s:4:\"file\";s:17:\"ampel-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:3285;}s:12:\"medium_large\";a:5:{s:4:\"file\";s:17:\"ampel-768x432.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:432;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:31759;}s:9:\"1536x1536\";a:5:{s:4:\"file\";s:18:\"ampel-1536x864.jpg\";s:5:\"width\";i:1536;s:6:\"height\";i:864;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:125919;}s:11:\"medium-16-9\";a:5:{s:4:\"file\";s:17:\"ampel-960x540.jpg\";s:5:\"width\";i:960;s:6:\"height\";i:540;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:54036;}s:10:\"small-16-9\";a:5:{s:4:\"file\";s:17:\"ampel-480x270.jpg\";s:5:\"width\";i:480;s:6:\"height\";i:270;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:12341;}s:9:\"large-1-1\";a:5:{s:4:\"file\";s:19:\"ampel-1200x1080.jpg\";s:5:\"width\";i:1200;s:6:\"height\";i:1080;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:103353;}s:10:\"medium-1-1\";a:5:{s:4:\"file\";s:17:\"ampel-600x600.jpg\";s:5:\"width\";i:600;s:6:\"height\";i:600;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:37713;}s:9:\"small-1-1\";a:5:{s:4:\"file\";s:17:\"ampel-300x300.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:300;s:9:\"mime-type\";s:10:\"image/jpeg\";s:8:\"filesize\";i:9682;}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"c