(235,	1,	'2023-09-06 12:49:20',	'2023-09-06 12:49:20',	'<!-- wp:paragraph -->\n<p>Du möchtest in einem interdisziplinären Team an aktuellen Fragen der Digitalisierung arbeiten und praktische Lösungen zu entwickeln?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Dann könnte D64 der richtige Ort für Dich sein. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bei uns treffen Expertise, Analyse und Praxis aufeinander. Wir schätzen sachliche Diskussionen und zielorientiertes Handeln, um den digitalen Fortschritt für alle nutzbar zu machen.</p>\n<!-- /wp:paragraph -->',	'Jobs',	'',	'trash',	'closed',	'closed',	'',	'jobs__trashed',	'',	'',	'2024-11-11 13:11:32',	'2024-11-11 13:11:32',	'',	0,	'http://localhost:10253/?page_id=235',	0,	'page',	'',	0),
