(287,	1,	'2023-09-08 16:59:31',	'2023-09-08 16:59:31',	'<!-- wp:image {\"id\":126,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"http://localhost:10253/wp-content/uploads/2023/09/D64_Geschaeftsstelle-1024x732.jpg\" alt=\"Die vier Mitglieder der Geschäftsstelle freundlich lächelnd im Garten.\" class=\"wp-image-126\"/><figcaption class=\"wp-element-caption\">Die Geschäftsstelle von D-64</figcaption></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"16px\"}}} -->\n<p style=\"font-size:16px\">Die Geschäftsstelle unterstützt und berät den Verein im Eintreten für eine progressive Gestaltung der digitalen Transformation. Dabei arbeitet sie eng mit Vorstand zusammen. Die Geschäftsstelle koordiniert Presse- und Terminanfragen nach außen und innen. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"16px\"}}} -->\n<p style=\"font-size:16px\">Sie ist per Email unter <a href=\"mailto:buero@d-64.org\">buero@d-64.org</a> oder telefonisch unter +49 30 – 577 142 56 erreichbar. Mitglieder können uns natürlich auch gerne im Vereinsheim ansprechen</p>\n<!-- /wp:paragraph -->',	'Geschäftsstelle',	'',	'inherit',	'closed',	'closed',	'',	'107-revision-v1',	'',	'',	'2023-09-08 16:59:31',	'2023-09-08 16:59:31',	'',	107,	'http://localhost:10253/?p=287',	0,	'revision',	'',	0),
