(20656,	1,	'2023-12-01 12:36:56',	'2023-12-01 12:36:56',	'<!-- wp:paragraph -->\n<p>D64 ist das Zentrum für digitalen Fortschritt.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"16px\"}}} -->\n<p style=\"font-size:16px\">Wir begreifen die digitale Transformation als große Chance, das Miteinander unserer modernen Gesellschaft zu verbessern. Die soziale, ökologische, technologische und politische Entwicklung wollen wir konstruktiv, kritisch und kreativ mitgestalten.</p>\n<!-- /wp:paragraph -->',	'Chronik',	'',	'inherit',	'closed',	'closed',	'',	'156-revision-v1',	'',	'',	'2023-12-01 12:36:56',	'2023-12-01 12:36:56',	'',	156,	'http://localhost:10253/?p=20656',	0,	'revision',	'',	0),
(20657,	1,	'2023-12-01 12:36:57',	'2023-12-01 12:36:57',	'<!-- wp:paragraph -->\n<p>D64 ist das Zentrum für digitalen Fortschritt.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"16px\"}}} -->\n<p style=\"font-size:16px\">Wir begreifen die digitale Transformation als große Chance, das Miteinander unserer modernen Gesellschaft zu verbessern. Die soziale, ökologische, technologische und politische Entwicklung wollen wir konstruktiv, kritisch und kreativ mitgestalten.</p>\n<!-- /wp:paragraph -->',	'Chronik',	'',	'inherit',	'closed',	'closed',	'',	'156-revision-v1',	'',	'',	'2023-12-01 12:36:57',	'2023-12-01 12:36:57',	'',	156,	'http://localhost:10253/?p=20657',	0,	'revision',	'',	0),
