(20670,	1,	'2023-12-08 15:15:07',	'2023-12-08 15:15:07',	'<!-- wp:paragraph -->\n<p>Der Beirat von D64 hat die Aufgabe, den Verein beratend zu unterstützen. 2023 wurde ein neuer Beirat berufen.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->',	'Beirat',	'',	'inherit',	'closed',	'closed',	'',	'274-revision-v1',	'',	'',	'2023-12-08 15:15:07',	'2023-12-08 15:15:07',	'',	274,	'http://localhost:10253/?p=20670',	0,	'revision',	'',	0),
