(20683,	1,	'2024-04-01 15:37:40',	'2024-04-01 15:37:40',	'a:11:{s:10:\"aria-label\";s:0:\"\";s:4:\"type\";s:4:\"text\";s:12:\"instructions\";s:0:\"\";s:8:\"required\";i:0;s:17:\"conditional_logic\";i:0;s:7:\"wrapper\";a:3:{s:5:\"width\";s:0:\"\";s:5:\"class\";s:0:\"\";s:2:\"id\";s:0:\"\";}s:13:\"default_value\";s:0:\"\";s:9:\"maxlength\";s:0:\"\";s:11:\"placeholder\";s:0:\"\";s:7:\"prepend\";s:0:\"\";s:6:\"append\";s:0:\"\";}',	'Text keine Beiträge',	'no-content',	'trash',	'closed',	'closed',	'',	'field_660ad482d3407__trashed',	'',	'',	'2024-11-22 09:53:45',	'2024-11-22 09:53:45',	'',	20682,	'http://localhost:10253/?post_type=acf-field&#038;p=20683',	0,	'acf-field',	'',	0),
(20684,	1,	'2024-04-01 15:39:03',	'2024-04-01 15:39:03',	'<!-- wp:paragraph -->\n<p>Du möchtest in einem interdisziplinären Team an aktuellen Fragen der Digitalisierung arbeiten und praktische Lösungen zu entwickeln?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Dann könnte D64 der richtige Ort für Dich sein. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bei uns treffen Expertise, Analyse und Praxis aufeinander. Wir schätzen sachliche Diskussionen und zielorientiertes Handeln, um den digitalen Fortschritt für alle nutzbar zu machen.</p>\n<!-- /wp:paragraph -->',	'Jobs',	'',	'inherit',	'closed',	'closed',	'',	'235-revision-v1',	'',	'',	'2024-04-01 15:39:03',	'2024-04-01 15:39:03',	'',	235,	'http://localhost:10253/?p=20684',	0,	'revision',	'',	0),
